import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function BillsHistory({ employee }) {
  const navigate = useNavigate();
  const [bills, setBills] = useState([]);
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");

  useEffect(() => {
    if (employee?.empld) fetchBills();
  }, [employee]);

  const fetchBills = async () => {
    try {
      const res = await fetch(
        `${apiBase}/bills?empld=${encodeURIComponent(employee.empld)}`
      );
      const data = await res.json();
      setBills(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error("Bills fetch error:", err);
    }
  };

  const filteredBills = bills.filter((b) => {
    const dateStr = b.created_at?.split?.("T")?.[0] || b.created_at;
    if (startDate && dateStr < startDate) return false;
    if (endDate && dateStr > endDate) return false;
    return true;
  });

  const handleDownloadPDF = () => window.print();

  if (!employee)
    return (
      <div style={centerScreen}>
        <div>No employee info. Please login again.</div>
      </div>
    );

  return (
    <div style={outerContainer}>
      <div style={card}>
        <div style={headerRow}>
          <button onClick={() => navigate("/history")} style={backBtn}>
            ⬅ Back
          </button>
          <h2 style={title}>Bills Upload History</h2>
        </div>

        <p style={empInfo}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* FILTERS */}
        <div style={filterBar}>
          <div style={filterBlock}>
            <span>From Date</span>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <div style={filterBlock}>
            <span>To Date</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <button
            onClick={() => {
              setStartDate("");
              setEndDate("");
            }}
            style={clearBtn}
          >
            Clear Filters
          </button>
        </div>

        {/* TABLE */}
        <table style={tableStyle}>
          <thead>
            <tr>
              <th>Date</th>
              <th>File Name</th>
              <th>Preview</th>
            </tr>
          </thead>

          <tbody>
            {filteredBills.map((b) => (
              <tr key={b.id}>
                <td>{b.created_at?.split?.("T")?.[0] || b.created_at}</td>
                <td>{b.fileName}</td>
                <td>
                  <a href={`${apiBase}${b.filePath}`} target="_blank">
                    Open
                  </a>
                </td>
              </tr>
            ))}

            {filteredBills.length === 0 && (
              <tr>
                <td colSpan="3" style={noData}>
                  No bills match your filters.
                </td>
              </tr>
            )}
          </tbody>
        </table>

        {/* PDF BUTTON LEFT, BOTTOM */}
        <div style={pdfRow}>
          <button onClick={handleDownloadPDF} style={downloadBtn}>
            Download PDF
          </button>
        </div>
      </div>
    </div>
  );
}

// ------- STYLES -------

const outerContainer = {
  minHeight: "100vh",
  background: lightGreen,
  padding: 20,
  fontFamily: "Segoe UI",
};

const centerScreen = {
  ...outerContainer,
  display: "flex",
  justifyContent: "center",
  alignItems: "center",
};

const card = {
  maxWidth: 950,
  margin: "0 auto",
  background: "#fff",
  borderRadius: 16,
  padding: 20,
  boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
};

const headerRow = { display: "flex", alignItems: "center", gap: 10 };

const backBtn = {
  background: "transparent",
  border: "none",
  color: green,
  fontSize: 16,
  cursor: "pointer",
};

const title = { color: green, margin: 0 };
const empInfo = { fontSize: 13, color: "#555", marginTop: 6 };

const filterBar = {
  display: "flex",
  gap: 10,
  flexWrap: "wrap",
  background: "#f9fff9",
  borderRadius: 10,
  border: "1px solid #eaf8f0",
  padding: 10,
  marginTop: 14,
  marginBottom: 14,
};

const filterBlock = { display: "flex", flexDirection: "column", fontSize: 12 };

const filterInput = {
  padding: "4px 6px",
  borderRadius: 6,
  border: "1px solid #ccc",
  fontSize: 12,
};

const clearBtn = {
  padding: "6px 10px",
  borderRadius: 8,
  border: "1px solid #ccc",
  background: "#fff",
  cursor: "pointer",
  fontSize: 12,
};

const tableStyle = {
  width: "100%",
  borderCollapse: "collapse",
  fontSize: 13,
};

const pdfRow = {
  display: "flex",
  justifyContent: "flex-start",
  marginTop: 20,
};

const downloadBtn = {
  padding: "8px 14px",
  borderRadius: 20,
  border: "none",
  background: green,
  color: "#fff",
  fontSize: 13,
  cursor: "pointer",
};

const noData = { textAlign: "center", padding: 10 };
